#define pb(x) push_back(x)
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh(x) while(x)
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=4e5+2;
int t,mod;
ll w[MAXN];
void pushup(int u)
{
	w[u]=(w[u*2]*w[u*2+1])%mod;
}
void build(int u,int l,int r)
{
	if(l==r)
    {
		w[u]=1;
		return ;
	}
	int mid=(l+r)/2;
	build(u*2,l,mid);
	build(u*2+1,mid+1,r);
	pushup(u);
	return ;
}
bool check1(int l,int r,int L,int R)
{
	return (L<=l)&&(r<=R);
}
bool check2(int l,int r,int L,int R)
{
	return (r<L)||(R<l);
}
void update(int u,int l,int r,int x,int k)
{
	if(check1(l,r,x,x)) w[u]=k;
	else if(!check2(l,r,x,x))
    {
		int mid=(l+r)/2;
		update(u*2,l,mid,x,k);
		update(u*2+1,mid+1,r,x,k);
		pushup(u);
	}
    else return ;
}
int main(void)
{
	t=read();
	while(t--)
    {
		int q=read();
        mod=read();
		build(1,1,q);
		FOR(i,1,q)
        {
			int op=read();
			if(op==1)
            {
				int m=read();
				update(1,1,q,i,m);
			}
            else
            {
				int id=read();
				update(1,1,q,id,1);
			}
			writeln(w[1]);
		}
	}
	return false;
}
